INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "リリ", 1, 0, 1, 1, 40011, 321, 125801, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 24001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "クリア", 1, 0, 2, 1, 40011, 322, 126001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 24001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "プレシア", 1, 0, 3, 1, 40011, 323, 126101, "んーと。\nこれ、あげる。\nはい", 24001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "リリ", 2, 0, 4, 1, 40011, 324, 125801, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 24001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "クリア", 2, 0, 5, 1, 40011, 325, 126001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 24001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (2, "プレシア", 2, 0, 6, 1, 40011, 326, 126101, "お兄。\nきてくれて、うれしい", 24001);
